// ===== PATCH: Player Hub reopen / collapse integration =====
(function() {
  var reopenBtn = document.getElementById('reopenHubBtn');
  var sidebar = document.getElementById('rightSidebar');
  var collapseBtn = document.getElementById('sidebarCollapseBtn');
  if (!reopenBtn || !sidebar || !collapseBtn) return;

  function isCollapsed() {
    return sidebar.classList.contains('sidebarCollapsed');
  }
  function updateReopenVisibility() {
    // Only show on desktop (sidebar visible in layout) when collapsed
    if (window.innerWidth > 980) {
      reopenBtn.classList.toggle('hidden', !isCollapsed());
    } else {
      reopenBtn.classList.add('hidden');
    }
  }
  // Intercept collapse btn to also update reopen btn
  collapseBtn.addEventListener('click', function() {
    setTimeout(updateReopenVisibility, 30);
  });
  reopenBtn.addEventListener('click', function() {
    if (isCollapsed()) {
      // Simulate a click on the collapse button to expand
      collapseBtn.click();
    }
  });
  window.addEventListener('resize', updateReopenVisibility);
  // Tab buttons inside the sidebar should work normally
  updateReopenVisibility();
  // Re-check after saved state loads
  setTimeout(updateReopenVisibility, 200);
})();

// ===== PATCH: Keybinds panel toggle =====
(function() {
  var toggleBtn = document.getElementById('showKeybindsBtn');
  var panel = document.getElementById('keybindsPanel');
  var closeBtn = document.getElementById('closeKeybindsPanelBtn');
  if (!toggleBtn || !panel) return;

  function openPanel() {
    panel.classList.remove('hidden');
    panel.setAttribute('aria-hidden', 'false');
    toggleBtn.classList.add('primary');
  }
  function closePanel() {
    panel.classList.add('hidden');
    panel.setAttribute('aria-hidden', 'true');
    toggleBtn.classList.remove('primary');
  }
  function togglePanel() {
    if (panel.classList.contains('hidden')) openPanel();
    else closePanel();
  }

  toggleBtn.addEventListener('click', function(e) {
    e.stopPropagation();
    togglePanel();
  });
  if (closeBtn) closeBtn.addEventListener('click', closePanel);

  // Close on outside click
  document.addEventListener('click', function(e) {
    if (!panel.classList.contains('hidden') && !panel.contains(e.target) && e.target !== toggleBtn) {
      closePanel();
    }
  });

  // Override ? key handling to also toggle this panel
  document.addEventListener('keydown', function(e) {
    if (e.target && (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA')) return;
    if (e.key === '?' || e.key === '/') {
      e.preventDefault();
      togglePanel();
    }
  }, true);
})();

// ===== PATCH: P key → play mode, keybind overrides =====
(function() {
  document.addEventListener('keydown', function(e) {
    if (e.target && (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.tagName === 'SELECT')) return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;
    var key = (e.code || '').toLowerCase();
    var k = e.key ? e.key.toLowerCase() : '';
    // P → play
    if ((key === 'keyp' || k === 'p') && !e.repeat) {
      var playBtn = document.getElementById('playModeBtn');
      if (playBtn && !playBtn.disabled) { playBtn.click(); e.preventDefault(); }
    }
    // L → levels (already done in script.min.js keybind system; this is a safety overlay)
    // No duplication needed — handled by existing keybind "openLevels"
  }, false);
})();

// ===== PATCH: Quick-access keybinds for Sign Up / Log In / Leaderboard via ? panel =====
// These are documented in the panel. The actual modals are opened by existing buttons.
// We just wire up extra global shortcuts as bonus.
(function() {
  document.addEventListener('keydown', function(e) {
    if (e.target && (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.tagName === 'SELECT')) return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;
    var k = (e.code || '').toLowerCase();
    if (e.repeat) return;
    // Shift+L → leaderboard
    if ((k === 'keyl') && e.shiftKey) {
      var btn = document.getElementById('openLeaderboardBtn');
      if (btn) btn.click();
      e.preventDefault();
    }
    // Shift+S → sign up (auth modal register tab)
    if ((k === 'keys') && e.shiftKey) {
      var regBtn = document.getElementById('authRegisterTopBtn');
      if (regBtn) regBtn.click();
      e.preventDefault();
    }
    // Shift+I → sign in (log in)
    if ((k === 'keyi') && e.shiftKey) {
      var loginBtn = document.getElementById('authAccountBtn');
      if (loginBtn) loginBtn.click();
      e.preventDefault();
    }
  }, false);
})();

// ===== PATCH: Update keybinds panel to show customized keybinds =====
(function() {
  // Sync the customizable binds (restart, toggleBuild, togglePlay, openSettings, openLevels)
  // with the displayed panel when it opens
  var showBtn = document.getElementById('showKeybindsBtn');
  if (!showBtn) return;
  showBtn.addEventListener('click', function() {
    try {
      var settings = JSON.parse(localStorage.getItem('SSB_SAVE_V2') || '{}');
      var kb = (settings.settings && settings.settings.keybinds) || {};
      var map = {restart: 'R', toggleBuild: 'B', togglePlay: 'P', openSettings: 'Escape→Esc', openLevels: 'L'};
      var panel = document.getElementById('keybindsPanel');
      if (!panel) return;
      panel.querySelectorAll('.keybindRow').forEach(function(row) {
        var span = row.querySelector('span');
        if (!span) return;
        var text = span.textContent;
        // Match rows by their label
        Object.keys(map).forEach(function(action) {
          var friendly = {restart:'Restart run',toggleBuild:'Build mode',togglePlay:'Start / Play mode',openSettings:'Close modal / Settings',openLevels:'Levels'}[action];
          if (text === friendly && kb[action]) {
            var kbd = row.querySelector('kbd');
            if (kbd) {
              var raw = kb[action];
              var display = raw === 'escape' ? 'Esc' : raw === 'space' ? 'Space' : raw.length === 1 ? raw.toUpperCase() : raw;
              kbd.textContent = display;
            }
          }
        });
      });
    } catch(e) {}
  });
})();

// ===== PATCH: Tab switching in Player Hub actually works =====
(function() {
  // Ensure rightTabCoinsBtn and rightTabCustomizationBtn are wired up
  // (they are wired in script.min.js via or() function, so this is a guard)
  var coinsBtn = document.getElementById('rightTabCoinsBtn');
  var custBtn = document.getElementById('rightTabCustomizationBtn');
  var coinsTab = document.getElementById('rightTabCoins');
  var custTab = document.getElementById('rightTabCustomization');
  if (!coinsBtn || !custBtn || !coinsTab || !custTab) return;

  function showTab(which) {
    var isCoins = which === 'coins';
    coinsTab.classList.toggle('hidden', !isCoins);
    custTab.classList.toggle('hidden', isCoins);
    coinsBtn.classList.toggle('primary', isCoins);
    coinsBtn.classList.toggle('active', isCoins);
    custBtn.classList.toggle('primary', !isCoins);
    custBtn.classList.toggle('active', !isCoins);
  }

  // Re-wire with capture so we guarantee the click fires
  coinsBtn.addEventListener('click', function() { showTab('coins'); }, true);
  custBtn.addEventListener('click', function() { showTab('customization'); }, true);
})();
